/**
 * Hand-written wrapper. DO NOT regenerate this file.
 *
 * The model data lives in `openrouter.models.json` (regenerated by
 * `fetch-openrouter-models.ts`). This wrapper re-exports it typed so
 * consumers can keep `import { models } from './openrouter.models'`.
 *
 * The data is loaded via `JSON.parse(readFileSync(...))` rather than an
 * `import ... with { type: 'json' }` attribute so the loader doesn't have
 * to support JSON import attributes.
 */

import { readFileSync } from 'node:fs'
import { dirname, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

export interface OpenRouterModel {
  id: string
  canonical_slug?: string
  hugging_face_id?: string | null
  name: string
  created?: number
  description?: string
  context_length: number
  architecture: {
    modality: string
    input_modalities: Array<string>
    output_modalities: Array<string>
    tokenizer?: string
    instruct_type?: string | null
  }

  pricing: {
    prompt: string
    completion: string
    audio?: string
    request?: string
    image?: string
    web_search?: string
    internal_reasoning?: string
    input_cache_read?: string
    input_cache_write?: string
  }
  top_provider: {
    context_length: number
    max_completion_tokens: number | null
    is_moderated: boolean
  }
  per_request_limits?: Record<string, string> | null
  supported_parameters?: Array<string>
}

const __dirname = dirname(fileURLToPath(import.meta.url))
const DATA_PATH = resolve(__dirname, 'openrouter.models.json')

export const models: Array<OpenRouterModel> = JSON.parse(
  readFileSync(DATA_PATH, 'utf-8'),
)
